package main

import("context";"encoding/json";"log";"net/http";"os";"time";"github.com/jackc/pgx/v5";"github.com/jackc/pgx/v5/pgxpool")
type line struct{ProductID string `json:"productId"`;Quantity int `json:"quantity"`;Price float64 `json:"price"`};type input struct{CustomerID string `json:"customerId"`;Items []line `json:"items"`;ShippingAddress map[string]any `json:"shippingAddress"`};type order struct{ID string `json:"id"`;CustomerID string `json:"customerId"`;Status string `json:"status"`;ShippingAddress map[string]any `json:"shippingAddress"`;Total float64 `json:"total"`;CreatedAt time.Time `json:"createdAt"`;Items []line `json:"items"`}
func reply(w http.ResponseWriter,s int,v any){w.Header().Set("Content-Type","application/json");w.WriteHeader(s);_=json.NewEncoder(w).Encode(v)}
func find(ctx context.Context,db *pgxpool.Pool,id string)(order,error){var o order;var a []byte;e:=db.QueryRow(ctx,`SELECT id,customer_id,status,shipping_address,total::float8,created_at FROM orders WHERE id=$1`,id).Scan(&o.ID,&o.CustomerID,&o.Status,&a,&o.Total,&o.CreatedAt);if e!=nil{return o,e};_=json.Unmarshal(a,&o.ShippingAddress);o.Items=[]line{};rows,e:=db.Query(ctx,`SELECT product_id,quantity,unit_price::float8 FROM order_items WHERE order_id=$1`,id);if e!=nil{return o,e};defer rows.Close();for rows.Next(){var x line;if e=rows.Scan(&x.ProductID,&x.Quantity,&x.Price);e!=nil{return o,e};o.Items=append(o.Items,x)};return o,rows.Err()}
func main(){ctx:=context.Background();db,e:=pgxpool.New(ctx,os.Getenv("DATABASE_URL"));if e!=nil{log.Fatal(e)};defer db.Close();_,e=db.Exec(ctx,`CREATE TABLE IF NOT EXISTS orders(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),customer_id varchar(320) NOT NULL,status varchar(40) NOT NULL,shipping_address jsonb NOT NULL DEFAULT '{}'::jsonb,total numeric(12,2) NOT NULL DEFAULT 0,created_at timestamptz NOT NULL DEFAULT now());CREATE TABLE IF NOT EXISTS order_items(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),order_id uuid NOT NULL REFERENCES orders(id) ON DELETE CASCADE,product_id varchar(120) NOT NULL,quantity integer NOT NULL CHECK(quantity>0),unit_price numeric(12,2) NOT NULL CHECK(unit_price>=0));CREATE INDEX IF NOT EXISTS orders_customer_id_idx ON orders(customer_id);CREATE INDEX IF NOT EXISTS order_items_order_id_idx ON order_items(order_id)`);if e!=nil{log.Fatal(e)};mux:=http.NewServeMux();mux.HandleFunc("GET /health",func(w http.ResponseWriter,r *http.Request){if db.Ping(r.Context())!=nil{reply(w,503,map[string]string{"service":"orders","status":"unavailable"});return};reply(w,200,map[string]string{"service":"orders","status":"ok"})});mux.HandleFunc("POST /",func(w http.ResponseWriter,r *http.Request){var in input;if json.NewDecoder(http.MaxBytesReader(w,r.Body,1<<20)).Decode(&in)!=nil||in.CustomerID==""||len(in.Items)==0{reply(w,400,map[string]string{"error":"customerId_and_valid_items_required"});return};total:=0.0;for _,x:=range in.Items{if x.ProductID==""||x.Quantity<1||x.Price<0{reply(w,400,map[string]string{"error":"customerId_and_valid_items_required"});return};total+=x.Price*float64(x.Quantity)};a,_:=json.Marshal(in.ShippingAddress);tx,e:=db.BeginTx(r.Context(),pgx.TxOptions{});if e!=nil{reply(w,500,map[string]string{"error":"order_creation_failed"});return};defer tx.Rollback(r.Context());var id string;e=tx.QueryRow(r.Context(),`INSERT INTO orders(customer_id,status,shipping_address,total) VALUES($1,'pending_payment',$2,$3) RETURNING id`,in.CustomerID,a,total).Scan(&id);if e==nil{for _,x:=range in.Items{_,e=tx.Exec(r.Context(),`INSERT INTO order_items(order_id,product_id,quantity,unit_price) VALUES($1,$2,$3,$4)`,id,x.ProductID,x.Quantity,x.Price);if e!=nil{break}}};if e==nil{e=tx.Commit(r.Context())};if e!=nil{log.Print(e);reply(w,500,map[string]string{"error":"order_creation_failed"});return};o,e:=find(r.Context(),db,id);if e!=nil{reply(w,500,map[string]string{"error":"order_read_failed"});return};reply(w,201,o)});mux.HandleFunc("GET /{id}",func(w http.ResponseWriter,r *http.Request){o,e:=find(r.Context(),db,r.PathValue("id"));if e!=nil{reply(w,404,map[string]string{"error":"order_not_found"});return};reply(w,200,o)});port:=os.Getenv("PORT");if port==""{port="4003"};log.Fatal(http.ListenAndServe(":"+port,mux))}
